/**
 * LLM-Powered Dynamic Expression Generator
 *
 * "Better than human" personality expressions generated by Gemini in the background.
 *
 * This is the next evolution beyond pool-based selection and building-block composition:
 * - Truly UNIQUE expressions every time (no repetition)
 * - PERSONA-GROUNDED via voice DNA injection
 * - NON-BLOCKING - runs on async queue in background
 * - PRE-GENERATION - fills cache during quiet moments
 * - COST-EFFICIENT - batching, caching, smart throttling
 *
 * Architecture:
 * 1. Expression queue - requests queued, processed in batches
 * 2. LLM worker - generates expressions with persona grounding
 * 3. Expression cache - stores generated expressions for reuse
 * 4. Fallback chain - LLM → Composed → Pool-based
 *
 * @module personas/bundles/ferni/llm-expression-generator
 */

import type { ThemeCategory } from '../../../services/session-variety-tracker.js';
import { createLogger } from '../../../utils/safe-logger.js';
import { cleanForFirestore } from '../../../utils/firestore-utils.js';
import { TEMP_CREATIVE, MAX_TOKENS_MEDIUM } from '../../../config/gemini-config.js';

// Pre-import these modules to avoid slow dynamic imports in hot path
// Note: These must be imported AFTER the types to avoid circular dependencies
let composeExpressionFn:
  | typeof import('../../shared/better-than-human-personality.js').composeExpression
  | null = null;
let getExpressionFn: typeof import('./dynamic-personality.js').getExpression | null = null;

// Initialize imports eagerly (runs once at module load)
void (async () => {
  try {
    const [personality, dynamic] = await Promise.all([
      import('../../shared/better-than-human-personality.js'),
      import('./dynamic-personality.js'),
    ]);
    composeExpressionFn = personality.composeExpression;
    getExpressionFn = dynamic.getExpression;
  } catch (e) {
    // Will fall back to dynamic import at runtime
  }
})();

const log = createLogger({ module: 'llm-expression-gen' });

// ============================================================================
// TYPES
// ============================================================================

export interface ExpressionRequest {
  id: string;
  theme: ThemeCategory;
  context: ExpressionContext;
  priority: 'high' | 'normal' | 'low';
  timestamp: number;
}

export interface ExpressionContext {
  /** User's current emotional state */
  emotion?: string;
  /** Current conversation topic */
  topic?: string;
  /** Time of day */
  timeOfDay?: 'dawn' | 'morning' | 'afternoon' | 'evening' | 'late_night' | 'night';
  /** Relationship depth */
  relationshipStage?: 'stranger' | 'acquaintance' | 'friend' | 'trusted_advisor';
  /** Recent topics for callbacks */
  recentTopics?: string[];
  /** Conversation momentum */
  momentum?: 'opening' | 'building' | 'cruising' | 'winding_down';
  /** Was this a heavy topic? */
  isHeavyTopic?: boolean;
}

export interface GeneratedExpression {
  id: string;
  theme: ThemeCategory;
  content: string;
  ssml: string;
  context: ExpressionContext;
  generatedAt: Date;
  usedCount: number;
}

// Note: GenerationBatch planned for future batch optimization
// interface GenerationBatch {
//   requests: ExpressionRequest[];
//   startedAt: number;
// }

